def parse_package_structure(tree_text):
    result = {}
    lines = tree_text.splitlines()
    stack = [(result, -1)]  # (current_dict, indent_level)

    for line in lines:
        if not line.strip():
            continue
        indent = len(line) - len(line.lstrip())
        level = indent // 4
        name = line.strip()

        # Pop stack to find parent
        while len(stack) > 1 and stack[-1][1] >= level:
            stack.pop()

        parent = stack[-1][0]

        if name.endswith('/'):
            dir_name = name.rstrip('/')
            parent[dir_name] = {}
            stack.append((parent[dir_name], level))
        else:
            parent[name] = None

    return result


def find_init_files(structure, path=''):
    result = []
    for name, value in structure.items():
        current_path = f'{path}/{name}' if path else name
        if name == '__init__.py':
            result.append(current_path)
        elif isinstance(value, dict):
            result.extend(find_init_files(value, current_path))
    return sorted(result)


def validate_package(structure):
    errors = []

    # Check single root directory
    top_level = [k for k in structure if isinstance(structure[k], dict)]
    if len(top_level) != 1:
        errors.append('Root must be a single directory')
        return {'valid': False, 'errors': errors}

    def check_dir(d, path):
        if '__init__.py' not in d:
            errors.append(f'Missing __init__.py in {path}')
        for name, value in d.items():
            if isinstance(value, dict):
                check_dir(value, f'{path}/{name}')
            elif value is None and not name.endswith('.py'):
                errors.append(f'Non-Python file: {path}/{name}')

    root_name = top_level[0]
    check_dir(structure[root_name], root_name)

    return {'valid': len(errors) == 0, 'errors': errors}


def generate_imports_for_package(package_name, modules):
    imports = []
    for mod in modules:
        if '.' in mod:
            parts = mod.rsplit('.', 1)
            imports.append(f'from {package_name}.{parts[0]} import {parts[1]}')
        else:
            imports.append(f'from {package_name} import {mod}')
    return sorted(imports)
